#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int a[N],n,dp[N],s[N],g[N];
inline int S(const int &l,const int &r){return s[r]-s[l-1];}
int main()
{
	n=read();drep(n,1,i)a[i]=read();rep(1,n,i)s[i]=s[i-1]+a[i];
	rep(1,n,i)
	{
		for(int j=i-1;~j;--j)if(g[j]<=s[i]-s[j])
		{
			dp[i]=dp[j]+1;
			g[i]=s[i]-s[j];break;
		}
	}
	printf("%d\n",dp[n]);
}
